pub fn retry<F, T, E>(attempts: u32, initial_delay: Duration, mut f: F) -> Result<T, E>
where
    F: FnMut() -> Result<T, E>,
{
    let mut delay = initial_delay;
    for i in 0..attempts {
        match f() {
            Ok(val) => return Ok(val),
            Err(e) => {
                if i == attempts - 1 { return Err(e); }
                std::thread::sleep(delay);
                delay *= 2;
            }
        }
    }
    unreachable!()
}

