def load_npy_as_uint8(path):
    """Load npy file, normalize to uint8."""
    arr = np.load(path).flatten().astype(float)
    smin, smax = arr.min(), arr.max()
    if smax - smin < 1e-10:
        return np.full(len(arr), 128, dtype=np.uint8).tobytes()
    if arr.dtype == np.uint8:
        return arr.tobytes()
    u8 = np.clip((arr - smin) / (smax - smin) * 255, 0, 255).astype(np.uint8)
    return u8.tobytes()

def load_wav_as_uint8(path):
    """Load WAV file, convert to uint8 waveform."""
    with wave.open(path, 'r') as w:
        frames = w.readframes(w.getnframes())
        samples = np.frombuffer(frames, dtype=np.int16).astype(float)
    # Normalize to 0-255
    smin, smax = samples.min(), samples.max()
    if smax - smin < 1:
        return np.full(len(samples), 128, dtype=np.uint8).tobytes()
    u8 = ((samples - smin) / (smax - smin) * 255).astype(np.uint8)
    return u8.tobytes()

def norm(arr):
    a = np.array(arr, dtype=float)
    a = np.where(np.isfinite(a), a, 0)
    amin, amax = a.min(), a.max()
    if amax - amin < 1e-10: return np.full(len(a), 0.5)
    return (a - amin) / (amax - amin)

def segment_wave(segments):
    """Build a 256-point waveform from piecewise segments.
    segments: list of (fraction_of_total, start_val, end_val, curvature)
    curvature: 1=linear, >1=convex, <1=concave, 'exp'=exponential
    """
    points = []
    for frac, v0, v1, curve in segments:
        n_pts = max(int(round(frac * N)), 1)
        local_t = np.linspace(0, 1, n_pts)
        if curve == 'exp':
            seg = v0 + (v1 - v0) * (np.exp(3 * local_t) - 1) / (np.e**3 - 1)
        elif isinstance(curve, (int, float)):
            seg = v0 + (v1 - v0) * local_t**curve
        else:
            seg = v0 + (v1 - v0) * local_t
        points.extend(seg.tolist())
    # Resample to exactly N points
    x_old = np.linspace(0, 1, len(points))
    x_new = np.linspace(0, 1, N)
    return np.interp(x_new, x_old, points)

