def extract_patterns_from_signal(signal, name, window=256, stride=64):
    """Extract substrate patterns from a signal via sliding window."""
    patterns = {}
    if len(signal) < 20:
        return patterns

    if len(signal) < window:
        w = np.interp(np.linspace(0, len(signal) - 1, 256),
                       np.arange(len(signal)), signal)
        wmin, wmax = w.min(), w.max()
        if wmax - wmin > 1e-10:
            patterns[f'{name}_full'] = (w - wmin) / (wmax - wmin)
        return patterns

    seen = set()
    count = 0
    for start in range(0, len(signal) - window, stride):
        chunk = signal[start:start + window]
        wmin, wmax = chunk.min(), chunk.max()
        if wmax - wmin < 1e-10:
            continue
        norm = (chunk - wmin) / (wmax - wmin)
        if len(norm) != 256:
            norm = np.interp(np.linspace(0, len(norm) - 1, 256),
                              np.arange(len(norm)), norm)
        fp = tuple(np.round(norm * 12).astype(int))
        if fp in seen:
            continue
        seen.add(fp)
        patterns[f'{name}_{count}'] = norm
        count += 1
    return patterns

def extract_numeric_columns(path, max_cols=10):
    """Extract all numeric columns from a CSV as signal arrays."""
    signals = {}
    try:
        with open(path, errors='replace') as f:
            sample = f.read(8192)
            f.seek(0)
            try:
                dialect = csv.Sniffer().sniff(sample)
            except csv.Error:
                dialect = 'excel'
            reader = csv.DictReader(f, dialect=dialect)
            columns = {}
            for row in reader:
                for key, val in row.items():
                    if key not in columns:
                        columns[key] = []
                    try:
                        columns[key].append(float(val))
                    except (ValueError, TypeError):
                        columns[key].append(None)

            col_count = 0
            for key, vals in columns.items():
                numeric = [v for v in vals if v is not None]
                if len(numeric) >= 20:  # Need at least 20 points
                    signals[key] = np.array(numeric)
                    col_count += 1
                    if col_count >= max_cols:
                        break
    except Exception as e:
        pass
    return signals
